bad_example:
result = {
    'job_id': uuid.uuid4(),          # UUID — not JSON serializable
    'started_at': datetime.utcnow(),  # datetime — not JSON serializable
    'score': Decimal('0.95'),         # Decimal — not JSON serializable
}
message = json.dumps(result)  # TypeError at runtime

good_example:
# Option A — safe catch-all (loses type fidelity, acceptable for logging/messaging)
message = json.dumps(result, default=str)

# Option B — explicit encoder (preserves semantics)
class _Enc(json.JSONEncoder):
    def default(self, o):
        if isinstance(o, (datetime, date)): return o.isoformat()
        if isinstance(o, UUID): return str(o)
        if isinstance(o, Decimal): return float(o)
        return super().default(o)
message = json.dumps(result, cls=_Enc)
